 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import { Action, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 5	import { DropdownItem, TooltipPosition } from '@patternfly/react-core';
 6	import MutedText from '@utils/components/MutedText/MutedText';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	
 9	import './action-dropdown-item.scss';
10	
11	type ActionDropdownItemProps = {
12	  action: Action;
13	  setIsOpen: Dispatch<SetStateAction<boolean>>;
14	};
15	
16	const ActionDropdownItem: FC<ActionDropdownItemProps> = ({ action, setIsOpen }) => {
17	  const { t } = useNetworkingTranslation();
18	  const [actionAllowed] = useAccessReview(action?.accessReview);
19	  const isCloneDisabled = !actionAllowed && action?.id === 'vm-action-clone';
20	
21	  const handleClick = () => {
22	    if (typeof action?.cta === 'function') {
23	      action?.cta();
24	      setIsOpen(false);
25	    }
26	  };
27	
28	  return (
29	    <DropdownItem
30	      data-test-id={`${action?.id}`}
31	      description={action?.description}
32	      isDisabled={action?.disabled || !actionAllowed}
33	      key={action?.id}
34	      onClick={handleClick}
35	      {...(isCloneDisabled && {
36	        tooltipProps: {
37	          content: t(`You don't have permission to perform this action`),
38	          position: TooltipPosition.left,
39	        },
40	      })}
41	      className={classNames({ ActionDropdownItem__disabled: isCloneDisabled })}
42	    >
43	      {action?.label}
44	      {action?.icon && (
45	        <>
46	          {' '}
47	          <MutedText content={action.icon} isSpan />
48	        </>
49	      )}
50	    </DropdownItem>
51	  );
52	};
53	
54	export default ActionDropdownItem;

